(function() {
    'use strict';

    // ================= LANGUAGE SYSTEM =================
    function getLanguage() {
        return localStorage.getItem('selectedLanguage') || 'en';
    }

    function applyLanguage(lang) {
        var elements = document.querySelectorAll('[data-en][data-mr]');
        elements.forEach(function(el) {
            var text = el.getAttribute('data-' + lang);
            if (text) {
                el.textContent = text;
            }
        });
        localStorage.setItem('selectedLanguage', lang);
        updateLanguageToggle(lang);
    }

    function updateLanguageToggle(lang) {
        var toggle = document.getElementById('languageToggle');
        var langTextEn = document.getElementById('langTextEn');
        var langTextMr = document.getElementById('langTextMr');
        
        if (toggle) {
            toggle.checked = (lang === 'mr');
        }
        
        if (langTextEn && langTextMr) {
            if (lang === 'mr') {
                langTextEn.classList.add('inactive');
                langTextMr.classList.remove('inactive');
            } else {
                langTextEn.classList.remove('inactive');
                langTextMr.classList.add('inactive');
            }
        }
    }

    function initLanguage() {
        var savedLang = getLanguage();
        applyLanguage(savedLang);
        
        var toggle = document.getElementById('languageToggle');
        if (toggle) {
            toggle.addEventListener('change', function() {
                var newLang = this.checked ? 'mr' : 'en';
                applyLanguage(newLang);
            });
        }
    }

    // ================= MOBILE MENU =================
    function initMobileMenu() {
        var hamburger = document.getElementById('hamburger');
        var navMenu = document.getElementById('navMenu');
        
        // Create overlay element dynamically
        var overlay = document.createElement('div');
        overlay.className = 'nav-overlay';
        document.body.appendChild(overlay);
        
        function toggleMenu() {
            hamburger.classList.toggle('active');
            navMenu.classList.toggle('active');
            overlay.classList.toggle('active');
            document.body.classList.toggle('nav-open');
        }
        
        function closeMenu() {
            hamburger.classList.remove('active');
            navMenu.classList.remove('active');
            overlay.classList.remove('active');
            document.body.classList.remove('nav-open');
        }
        
        if (hamburger && navMenu) {
            hamburger.addEventListener('click', toggleMenu);
            overlay.addEventListener('click', closeMenu);
        }
        
        var dropdownParents = document.querySelectorAll('.has-dropdown');
        
        dropdownParents.forEach(function(parent) {
            var toggleLink = parent.querySelector('.dropdown-toggle');
            
            if (toggleLink) {
                toggleLink.addEventListener('click', function(e) {
                    if (window.innerWidth <= 992) {
                        e.preventDefault();
                        e.stopPropagation();
                        parent.classList.toggle('active');
                    }
                });
            }
        });
        
        document.addEventListener('click', function(e) {
            if (window.innerWidth <= 992) {
                if (navMenu && hamburger && 
                    !navMenu.contains(e.target) && 
                    !hamburger.contains(e.target)) {
                    closeMenu();
                }
            }
        });
        
        window.addEventListener('resize', function() {
            if (window.innerWidth > 992 && navMenu && hamburger) {
                closeMenu();
                
                document.querySelectorAll('.has-dropdown').forEach(function(parent) {
                    parent.classList.remove('active');
                });
            }
        });
        
        // Close menu when clicking on a nav link
        var navLinks = document.querySelectorAll('.nav-link:not(.dropdown-toggle)');
        navLinks.forEach(function(link) {
            link.addEventListener('click', function() {
                if (window.innerWidth <= 992) {
                    closeMenu();
                }
            });
        });
    }

    // ================= PRINCIPAL MODAL =================
    function openModal() {
        var modal = document.getElementById('principalModal');
        if (modal) {
            modal.style.display = 'flex';
        }
    }

    function closeModal() {
        var modal = document.getElementById('principalModal');
        if (modal) {
            modal.style.display = 'none';
        }
    }

    window.openModal = openModal;
    window.closeModal = closeModal;

    document.addEventListener('click', function(event) {
        var modal = document.getElementById('principalModal');
        if (event.target === modal) {
            closeModal();
        }
    });

    // ================= IMAGE SLIDER =================
    function initSlider() {
        var slides = document.querySelectorAll('.slide');
        
        if (slides.length > 0) {
            var currentSlide = 0;
            
            function showSlide(index) {
                slides.forEach(function(slide) {
                    slide.classList.remove('active');
                });
                slides[index].classList.add('active');
            }
            
            function nextSlide() {
                currentSlide = (currentSlide + 1) % slides.length;
                showSlide(currentSlide);
            }
            
            setInterval(nextSlide, 3000);
        }
    }

    // ================= COUNTER ANIMATION (for department pages) =================
    function initCounters() {
        var counters = document.querySelectorAll('.stat-number');
        
        if (counters.length === 0) return;

        var observer = new IntersectionObserver(function(entries) {
            entries.forEach(function(entry) {
                if (entry.isIntersecting) {
                    animateCounter(entry.target);
                    observer.unobserve(entry.target);
                }
            });
        }, { threshold: 0.5 });

        counters.forEach(function(counter) {
            observer.observe(counter);
        });
    }

    function animateCounter(element) {
        var text = element.textContent;
        var match = text.match(/(\d+)/);
        
        if (!match) return;

        var finalNumber = parseInt(match[0]);
        var suffix = text.replace(/(\d+)/, '').trim();
        
        var current = 0;
        var duration = 2000;
        var steps = 60;
        var increment = finalNumber / steps;
        var stepTime = duration / steps;
        
        var timer = setInterval(function() {
            current += increment;
            
            if (current >= finalNumber) {
                current = finalNumber;
                element.textContent = current + suffix;
                clearInterval(timer);
                return;
            }
            
            element.textContent = Math.floor(current) + suffix;
        }, stepTime);
    }

    // ================= SMOOTH SCROLL =================
    function initSmoothScroll() {
        document.querySelectorAll('a[href^="#"]').forEach(function(anchor) {
            anchor.addEventListener('click', function(e) {
                var href = this.getAttribute('href');
                if (href === '#') return;
                
                var target = document.querySelector(href);
                if (target) {
                    e.preventDefault();
                    target.scrollIntoView({ behavior: 'smooth', block: 'start' });
                }
            });
        });
    }

    // ================= INITIALIZE ALL =================
    document.addEventListener('DOMContentLoaded', function() {
        initLanguage();
        initMobileMenu();
        initSlider();
        initCounters();
        initSmoothScroll();
        
        console.log('Suhas Institute Website Loaded Successfully!');
    });

})();
